static int select_best_network(zigbee_device_context_t *dev)
{
    int best_index = -1;
    uint8_t best_lqi = 0;

    for (uint8_t i = 0; i < dev->num_discovered_networks; i++) {
        zigbee_network_descriptor_t *net = &dev->discovered_networks[i];

        /* Must have permit joining enabled */
        if (!net->permit_joining) {
            printf("[NETWORK] Network %d: permit join disabled, skipping\n", i);
            continue;
        }

        /* Must have security enabled for smart home */
        if (!net->has_security) {
            printf("[NETWORK] Network %d: no security, skipping\n", i);
            continue;
        }

        /* Must be ZigBee PRO stack profile */
        if (net->stack_profile != 2) {
            printf("[NETWORK] Network %d: wrong stack profile (%u), skipping\n",
                   i, net->stack_profile);
            continue;
        }

        /* Prefer specific PAN if configured */
        if (dev->commissioning.preferred_pan_id != ZIGBEE_PAN_ID_BROADCAST &&
            net->pan_id == dev->commissioning.preferred_pan_id) {
            printf("[NETWORK] Network %d: matches preferred PAN ID\n", i);
            return i;
        }

        /* Select by best LQI */
        if (net->lqi > best_lqi) {
            best_lqi = net->lqi;
            best_index = i;
        }
    }

    if (best_index >= 0) {
        printf("[NETWORK] Selected network %d (LQI: %u)\n", best_index, best_lqi);
    }

    return best_index;
}

/* ---------- Network Joining ---------- */

static bool send_association_request(zigbee_device_context_t *dev,
                                      const zigbee_network_descriptor_t *network)
{
    printf("[JOIN] Sending Association Request to PAN 0x%04X on channel %u\n",
           network->pan_id, network->channel);

    /* Build MAC Association Request frame */
    uint8_t frame[32];
    uint8_t frame_len = 0;

    /* Frame Control: Command frame, request ACK, src/dst addr mode */
    frame[frame_len++] = 0x23;
    frame[frame_len++] = 0xC8;

    /* Sequence Number */
    frame[frame_len++] = 0x01;

    /* Destination PAN ID */
    frame[frame_len++] = (uint8_t)(network->pan_id & 0xFF);
    frame[frame_len++] = (uint8_t)(network->pan_id >> 8);

    /* Destination Address (coordinator: 0x0000) */
    frame[frame_len++] = 0x00;
    frame[frame_len++] = 0x00;

    /* Source PAN ID (broadcast during association) */
    frame[frame_len++] = 0xFF;
    frame[frame_len++] = 0xFE;

    /* Source EUI-64 */
    memcpy(&frame[frame_len], dev->eui64, ZIGBEE_EUI64_SIZE);
    frame_len += ZIGBEE_EUI64_SIZE;

    /* Command ID: Association Request */
    frame[frame_len++] = 0x01;

    /* Capability Information: mains power, rx on idle, allocate address */
    frame[frame_len++] = 0x8E;

    return radio_send_frame(frame, frame_len);
}

static bool process_association_response(zigbee_device_context_t *dev,
                                          uint16_t *assigned_address,
                                          uint8_t *status)
{
    /* Simulated response: successful association */
    *assigned_address = 0x1234;
    *status = 0x00; /* Association successful */

    printf("[JOIN] Association Response: address=0x%04X, status=0x%02X\n",
           *assigned_address, *status);

    return (*status == 0x00);
}

static bool perform_trust_center_key_exchange(zigbee_device_context_t *dev)
{
    printf("[JOIN] Starting Trust Center key exchange...\n");

    /* Step 1: Send Transport Key request (implicit via association) */
    printf("[JOIN] Waiting for Trust Center to send Transport Key...\n");
    hal_delay_ms(500);

    /* Simulated: TC sends encrypted network key using our pre-shared link key */
    uint8_t encrypted_network_key[ZIGBEE_NETWORK_KEY_SIZE] = {
        0xAA, 0xBB, 0xCC, 0xDD, 0xEE, 0xFF, 0x11, 0x22,
        0x33, 0x44, 0x55, 0x66, 0x77, 0x88, 0x99, 0x00
    };

    if (!security_decrypt_network_key(&dev->security, encrypted_network_key, 0)) {
        printf("[JOIN] Failed to decrypt network key!\n");
        return false;
    }

    /* Step 2: Verify network key by sending encrypted Device Announce */
    printf("[JOIN] Sending encrypted Device Announce...\n");

    uint8_t announce_frame[32];
    uint8_t announce_len = 0;

    /* NWK Header */
    announce_frame[announce_len++] = 0x08; /* Frame type: command */
    announce_frame[announce_len++] = 0x00;

    /* Destination: broadcast */
    announce_frame[announce_len++] = 0xFF;
    announce_frame[announce_len++] = 0xFD;

    /* Source */
    announce_frame[announce_len++] = (uint8_t)(dev->short_address & 0xFF);
    announce_frame[announce_len++] = (uint8_t)(dev->short_address >> 8);

    /* Device Announce ZDP command */
    announce_frame[announce_len++] = 0x13; /* Device_annce cluster */
    announce_frame[announce_len++] = 0x00;

    /* NWK address */
    announce_frame[announce_len++] = (uint8_t)(dev->short_address & 0xFF);
    announce_frame[announce_len++] = (uint8_t)(dev->short_address >> 8);

    /* IEEE address */
    memcpy(&announce_frame[announce_len], dev->eui64, ZIGBEE_EUI64_SIZE);
    announce_len += ZIGBEE_EUI64_SIZE;

    /* Capability */
    announce_frame[announce_len++] = 0x8E;

    security_encrypt_frame(&dev->security, announce_frame, &announce_len);
    radio_send_frame(announce_frame, announce_len);

    /* Step 3: If using R21+, perform Trust Center Link Key Update */
    printf("[JOIN] Requesting Trust Center Link Key Update (R21+)...\n");
    hal_delay_ms(200);

    /* Simulated: TC sends a unique link key for this device */
    uint8_t unique_link_key[ZIGBEE_LINK_KEY_SIZE];
    hal_generate_random(unique_link_key, ZIGBEE_LINK_KEY_SIZE);

    /* In real implementation: this would be decrypted with the old link key */
    memcpy(dev->security.trust_center_link_key, unique_link_key, ZIGBEE_LINK_KEY_SIZE);
    printf("[JOIN] Trust Center Link Key updated to device-unique key\n");

    /* Step 4: Send Verify Key (TCLK update confirmation) */
    printf("[JOIN] Sending Verify-Key confirmation to Trust Center\n");
    hal_delay_ms(100);

    printf("[JOIN] Trust Center key exchange completed successfully\n");
    return true;
}

static zigbee_join_status_t join_network(zigbee_device_context_t *dev,
                                          const zigbee_network_descriptor_t *network)
{
    printf("\n[JOIN] ========================================\n");
    printf("[JOIN] Attempting to join network:\n");
    printf("[JOIN]   PAN ID:  0x%04X\n", network->pan_id);
    printf("[JOIN]   Channel: %u\n", network->channel);
    printf("[JOIN] ========================================\n");

    /* Set radio to target channel and PAN */
    if (!radio_set_channel(network->channel)) {
        printf("[JOIN] Failed to set channel\n");
        return JOIN_STATUS_UNKNOWN_ERROR;
    }

    if (!radio_set_pan_id(network->pan_id)) {
        printf("[JOIN] Failed to set PAN ID\n");
        return JOIN_STATUS_UNKNOWN_ERROR;
    }

    /* Check permit joining */
    if (!network->permit_joining) {
        printf("[JOIN] Network does not permit joining\n");
        return JOIN_STATUS_PERMIT_JOIN_OFF;
    }

    dev->device_state = DEVICE_STATE_JOINING;

    /* Send association request */
    if (!send_association_request(dev, network)) {
        printf("[JOIN] Failed to send association request\n");
        return JOIN_STATUS_UNKNOWN_ERROR;
    }

    /* Wait for and process association response */
    hal_delay_ms(1000);
    uint16_t assigned_address;
    uint8_t assoc_status;

    dev->device_state = DEVICE_STATE_AUTHENTICATING;

    if (!process_association_response(dev, &assigned_address, &assoc_status)) {
        printf("[JOIN] Association failed (status: 0x%02X)\n", assoc_status);
        if (assoc_status == 0x01) return JOIN_STATUS_CAPACITY_FULL;
        if (assoc_status == 0x02) return JOIN_STATUS_AUTH_FAILED;
        return JOIN_STATUS_UNKNOWN_ERROR;
    }

    /* Store assigned address */
    dev->short_address = assigned_address;
    radio_set_short_address(assigned_address);

    printf("[JOIN] Association successful! Short address: 0x%04X\n", assigned_address);

    /* Perform security key exchange */
    dev->device_state = DEVICE_STATE_KEY_EXCHANGE;

    if (!perform_trust_center_key_exchange(dev)) {
        printf("[JOIN] Trust Center key exchange failed\n");
        return JOIN_STATUS_KEY_MISMATCH;
    }

    /* Store network parameters */
    dev->pan_id = network->pan_id;
    dev->extended_pan_id = network->extended_pan_id;
    dev->channel = network->channel;
    dev->device_state = DEVICE_STATE_JOINED;

    printf("[JOIN] Successfully joined network!\n");
    return JOIN_STATUS_SUCCESS;
}

