typedef struct {
    bool     active;
    uint16_t duration_seconds;
    uint32_t start_time;
    bool     broadcast_sent;
} permit_join_state_t;

static permit_join_state_t g_permit_join;

static bool permit_join_enable(zigbee_device_context_t *dev, uint16_t duration_seconds)
{
    if (dev->device_state != DEVICE_STATE_OPERATIONAL &&
        dev->device_state != DEVICE_STATE_JOINED) {
        printf("[PERMIT_JOIN] Cannot enable - device not on network\n");
        return false;
    }

    g_permit_join.active = true;
    g_permit_join.duration_seconds = duration_seconds;
    g_permit_join.start_time = hal_get_tick_ms();
    g_permit_join.broadcast_sent = false;

    printf("[PERMIT_JOIN] Enabled for %u seconds\n", duration_seconds);

    /* Send Mgmt_Permit_Joining_req to coordinator */
    uint8_t frame[16];
    uint8_t frame_len = 0;

    /* ZDP Mgmt_Permit_Joining_req (cluster 0x0036) */
    frame[frame_len++] = 0x36;
    frame[frame_len++] = 0x00;

    /* Transaction sequence */
    frame[frame_len++] = 0x01;

    /* Permit duration */
    frame[frame_len++] = (uint8_t)(duration_seconds & 0xFF);

    /* TC_Significance: 0x01 = update TC policy */
    frame[frame_len++] = 0x01;

    security_encrypt_frame(&dev->security, frame, &frame_len);
    radio_send_frame(frame, frame_len);

    printf("[PERMIT_JOIN] Mgmt_Permit_Joining_req sent to coordinator\n");

    /* Also broadcast to all routers */
    printf("[PERMIT_JOIN] Broadcasting permit join to all routers\n");
    g_permit_join.broadcast_sent = true;

    return true;
}

