/* ---------- Network Commissioning State Machine ---------- */

typedef enum {
    COMMISSION_IDLE = 0,
    COMMISSION_NETWORK_STEERING,
    COMMISSION_FINDING_BINDING,
    COMMISSION_TOUCHLINK,
    COMMISSION_COMPLETE,
    COMMISSION_FAILED
} commissioning_state_t;

typedef struct {
    commissioning_state_t state;
    uint8_t  step;
    uint8_t  retry_count;
    uint32_t state_enter_time;
    bool     steering_complete;
    bool     f_and_b_complete;
} commissioning_context_t;

static commissioning_context_t g_commissioning;

static void commissioning_init(commissioning_context_t *ctx)
{
    memset(ctx, 0, sizeof(commissioning_context_t));
    ctx->state = COMMISSION_IDLE;
    printf("[COMMISSION] Commissioning engine initialized\n");
}

static void commissioning_start_network_steering(zigbee_device_context_t *dev)
{
    printf("\n[COMMISSION] ====== Starting Network Steering ======\n");
    g_commissioning.state = COMMISSION_NETWORK_STEERING;
    g_commissioning.step = 0;
    g_commissioning.retry_count = 0;
    g_commissioning.state_enter_time = hal_get_tick_ms();
    dev->network_steering_active = true;
}

static bool commissioning_network_steering_tick(zigbee_device_context_t *dev)
{
    switch (g_commissioning.step) {
        case 0: {
            /* Step 1: Scan for networks */
            printf("[COMMISSION] Step 1: Scanning for open networks...\n");

            /* Scan all channels */
            uint32_t channel_mask = 0;
            for (uint8_t ch = ZIGBEE_CHANNEL_MIN; ch <= ZIGBEE_CHANNEL_MAX; ch++) {
                channel_mask |= (1UL << ch);
            }

            uint8_t found = network_scan(dev, channel_mask);
            if (found == 0) {
                printf("[COMMISSION] No networks found\n");
                g_commissioning.retry_count++;
                if (g_commissioning.retry_count >= dev->commissioning.max_join_retries) {
                    printf("[COMMISSION] Max retries exceeded\n");
                    g_commissioning.state = COMMISSION_FAILED;
                    return false;
                }
                hal_delay_ms(2000);
                return true; /* Retry scan */
            }
            g_commissioning.step = 1;
            return true;
        }

        case 1: {
            /* Step 2: Select best network */
            printf("[COMMISSION] Step 2: Selecting best network...\n");
            dev->selected_network_index = select_best_network(dev);

            if (dev->selected_network_index < 0) {
                printf("[COMMISSION] No suitable network found\n");
                g_commissioning.retry_count++;
                if (g_commissioning.retry_count >= dev->commissioning.max_join_retries) {
                    g_commissioning.state = COMMISSION_FAILED;
                    return false;
                }
                g_commissioning.step = 0; /* Go back to scanning */
                hal_delay_ms(5000);
                return true;
            }
            g_commissioning.step = 2;
            return true;
        }

        case 2: {
            /* Step 3: Join the selected network */
            printf("[COMMISSION] Step 3: Joining network...\n");
            zigbee_network_descriptor_t *target =
                &dev->discovered_networks[dev->selected_network_index];

            zigbee_join_status_t status = join_network(dev, target);
            dev->last_join_status = status;

            if (status != JOIN_STATUS_SUCCESS) {
                printf("[COMMISSION] Join failed (status: %d)\n", status);
                g_commissioning.retry_count++;
                if (g_commissioning.retry_count >= dev->commissioning.max_join_retries) {
                    g_commissioning.state = COMMISSION_FAILED;
                    return false;
                }
                g_commissioning.step = 0; /* Restart from scan */
                hal_delay_ms(3000);
                return true;
            }
            g_commissioning.step = 3;
            return true;
        }

        case 3: {
            /* Step 4: Register endpoints and enable permit join for sub-devices */
            printf("[COMMISSION] Step 4: Registering endpoints...\n");
            register_endpoints(dev);

            /* Enable permit join briefly for finding & binding */
            permit_join_enable(dev, ZIGBEE_PERMIT_JOIN_DURATION);

            dev->device_state = DEVICE_STATE_OPERATIONAL;
            g_commissioning.steering_complete = true;
            g_commissioning.step = 4;
            return true;
        }

        case 4: {
            /* Step 5: Network steering complete */
            printf("[COMMISSION] Network steering complete!\n");
            dev->network_steering_active = false;
            g_commissioning.state = COMMISSION_FINDING_BINDING;
            g_commissioning.step = 0;
            return true;
        }

        default:
            return false;
    }
}

static bool commissioning_finding_binding_tick(zigbee_device_context_t *dev)
{
    switch (g_commissioning.step) {
        case 0: {
            printf("\n[COMMISSION] ====== Starting Finding & Binding ======\n");
            printf("[F&B] Identifying as target for 180 seconds...\n");
            dev->finding_and_binding_active = true;

            /* Send Identify command to put device in identify mode */
            /* This allows controllers to discover and bind to our clusters */
            printf("[F&B] Sending ZDO Match_Desc_req for binding targets...\n");
            g_commissioning.step = 1;
            return true;
        }

        case 1: {
            /* Wait for binding responses */
            printf("[F&B] Waiting for binding responses...\n");
            hal_delay_ms(1000);

            /* Simulated: received a binding from a light switch */
            printf("[F&B] Received binding from device 0x0001 (switch)\n");
            printf("[F&B]   Cluster: On/Off (0x0006)\n");
            printf("[F&B]   Binding added successfully\n");

            g_commissioning.step = 2;
            return true;
        }

        case 2: {
            printf("[F&B] Finding & Binding complete\n");
            dev->finding_and_binding_active = false;
            g_commissioning.f_and_b_complete = true;
            g_commissioning.state = COMMISSION_COMPLETE;
            return true;
        }

        default:
            return false;
    }
}

static bool commissioning_tick(zigbee_device_context_t *dev)
{
    switch (g_commissioning.state) {
        case COMMISSION_IDLE:
            return false;

        case COMMISSION_NETWORK_STEERING:
            return commissioning_network_steering_tick(dev);

        case COMMISSION_FINDING_BINDING:
            return commissioning_finding_binding_tick(dev);

        case COMMISSION_COMPLETE:
            printf("\n[COMMISSION] ====================================\n");
            printf("[COMMISSION]  COMMISSIONING COMPLETE\n");
            printf("[COMMISSION]  Device is operational!\n");
            printf("[COMMISSION]  PAN: 0x%04X, CH: %u, Addr: 0x%04X\n",
                   dev->pan_id, dev->channel, dev->short_address);
            printf("[COMMISSION] ====================================\n\n");

            /* Save configuration to NVM */
            hal_save_to_nvm(dev, sizeof(zigbee_device_context_t));
            dev->is_factory_new = false;

            g_commissioning.state = COMMISSION_IDLE;
            return false;

        case COMMISSION_FAILED:
            printf("\n[COMMISSION] COMMISSIONING FAILED after %u attempts\n",
                   g_commissioning.retry_count);
            printf("[COMMISSION] Last join status: %d\n", dev->last_join_status);

            /* Visual indication: blink LED rapidly for error */
            for (int i = 0; i < 10; i++) {
                hal_set_led_state(true);
                hal_delay_ms(100);
                hal_set_led_state(false);
                hal_delay_ms(100);
            }

            g_commissioning.state = COMMISSION_IDLE;
            return false;

        default:
            return false;
    }
}

/* ---------- Factory Reset ---------- */

static void factory_reset(zigbee_device_context_t *dev)
{
    printf("\n[FACTORY RESET] Performing factory reset...\n");

    /* Leave current network if joined */
    if (dev->device_state == DEVICE_STATE_OPERATIONAL ||
        dev->device_state == DEVICE_STATE_JOINED) {
        printf("[FACTORY RESET] Sending network leave request...\n");

        uint8_t leave_frame[8];
        uint8_t leave_len = 0;
        leave_frame[leave_len++] = 0x34; /* Mgmt_Leave_req */
        leave_frame[leave_len++] = 0x00;
        leave_frame[leave_len++] = 0x03; /* Seq */
        memcpy(&leave_frame[leave_len], dev->eui64, ZIGBEE_EUI64_SIZE);
        leave_len += ZIGBEE_EUI64_SIZE;
        leave_frame[leave_len++] = 0x00; /* Options: no rejoin */

        radio_send_frame(leave_frame, leave_len);
        hal_delay_ms(500);
    }

    /* Clear all state */
    memset(&dev->security, 0, sizeof(zigbee_security_context_t));
    dev->short_address = 0xFFFE;
    dev->pan_id = ZIGBEE_PAN_ID_BROADCAST;
    dev->extended_pan_id = 0;
    dev->channel = 0;
    dev->device_state = DEVICE_STATE_INIT;
    dev->is_factory_new = true;
    dev->last_join_status = JOIN_STATUS_SUCCESS;
    dev->join_retry_count = 0;
    dev->num_discovered_networks = 0;

    /* Reset light to defaults */
    light_bulb_init(&dev->light);

    /* Clear NVM */
    hal_save_to_nvm(dev, sizeof(zigbee_device_context_t));

    printf("[FACTORY RESET] Complete. Device is factory new.\n");

    /* Visual indication: slow pulse */
    for (int i = 0; i < 3; i++) {
        hal_set_led_state(true);
        hal_delay_ms(500);
        hal_set_led_state(false);
        hal_delay_ms(500);
    }
}

/* ---------- LED Status Indication ---------- */

static void update_status_indication(zigbee_device_context_t *dev)
{
    static uint32_t last_blink = 0;
    static bool blink_state = false;
    uint32_t now = hal_get_tick_ms();

    switch (dev->device_state) {
        case DEVICE_STATE_INIT:
        case DEVICE_STATE_SCANNING:
            /* Fast blink: searching for network */
            if (now - last_blink > 250) {
                blink_state = !blink_state;
                hal_set_led_state(blink_state);
                last_blink = now;
            }
            break;

        case DEVICE_STATE_JOINING:
        case DEVICE_STATE_AUTHENTICATING:
        case DEVICE_STATE_KEY_EXCHANGE:
            /* Medium blink: joining */
            if (now - last_blink > 500) {
                blink_state = !blink_state;
                hal_set_led_state(blink_state);
                last_blink = now;
            }
            break;

        case DEVICE_STATE_JOINED:
            /* Slow blink: joined but not yet operational */
            if (now - last_blink > 1000) {
                blink_state = !blink_state;
                hal_set_led_state(blink_state);
                last_blink = now;
            }
            break;

        case DEVICE_STATE_OPERATIONAL:
            /* Steady: follow light bulb state */
            light_apply_state(&dev->light);
            break;

        case DEVICE_STATE_ERROR:
            /* Triple blink pattern */
            if (now - last_blink > 100) {
                static int error_count = 0;
                blink_state = !blink_state;
                hal_set_led_state(blink_state);
                last_blink = now;
                error_count++;
                if (error_count >= 6) {
                    hal_delay_ms(1000);
                    error_count = 0;
                }
            }
            break;

        default:
            break;
    }
}

/* ---------- Device Initialization ---------- */

static void device_init(zigbee_device_context_t *dev)
{
    printf("\n");
    printf("=============================================\n");
    printf("  Zigbee Smart Light Bulb - Firmware v1.0\n");
    printf("  Consumer-Friendly Smart Home Device\n");
    printf("=============================================\n\n");

    memset(dev, 0, sizeof(zigbee_device_context_t));

    /* Set device EUI-64 (unique identifier) */
    dev->eui64[0] = 0x00;
    dev->eui64[1] = 0x12;
    dev->eui64[2] = 0x4B;
    dev->eui64[3] = 0x00;
    dev->eui64[4] = 0x0A;
    dev->eui64[5] = 0xBC;
    dev->eui64[6] = 0xDE;
    dev->eui64[7] = 0xF0;

    dev->short_address = 0xFFFE; /* Not assigned yet */
    dev->endpoint = ZIGBEE_ENDPOINT_LIGHT;
    dev->device_state = DEVICE_STATE_INIT;
    dev->pan_id = ZIGBEE_PAN_ID_BROADCAST;

    /* Check if we have saved configuration */
    zigbee_device_context_t saved_config;
    if (hal_load_from_nvm(&saved_config, sizeof(saved_config))) {
        printf("[INIT] Found saved configuration, restoring...\n");
        memcpy(dev, &saved_config, sizeof(zigbee_device_context_t));
        dev->is_factory_new = false;
    } else {
        printf("[INIT] No saved configuration, device is factory new\n");
        dev->is_factory_new = true;
    }

    /* Default commissioning configuration */
    dev->commissioning.use_install_code = false;
    dev->commissioning.use_centralized_security = true;
    dev->commissioning.auto_join_on_power = true;
    dev->commissioning.preferred_pan_id = ZIGBEE_PAN_ID_BROADCAST; /* Any */
    dev->commissioning.preferred_channel = 0; /* Any */
    dev->commissioning.permit_join_timeout = ZIGBEE_PERMIT_JOIN_DURATION;
    dev->commissioning.max_join_retries = ZIGBEE_MAX_RETRIES;

    /* Initialize security with HA Trust Center Link Key */
    security_init(&dev->security, SECURITY_MODE_HA);

    /* Initialize radio */
    radio_init(ZIGBEE_DEFAULT_CHANNEL);

    /* Initialize light bulb */
    light_bulb_init(&dev->light);

    /* Initialize commissioning engine */
    commissioning_init(&g_commissioning);

    /* Initialize permit join state */
    memset(&g_permit_join, 0, sizeof(g_permit_join));

    printf("[INIT] Device EUI-64: ");
    for (int i = 0; i < ZIGBEE_EUI64_SIZE; i++) {
        printf("%02X", dev->eui64[i]);
        if (i < ZIGBEE_EUI64_SIZE - 1) printf(":");
    }
    printf("\n");

    printf("[INIT] Initialization complete\n\n");
}

/* ---------- Main Application Loop ---------- */

static void process_incoming_commands(zigbee_device_context_t *dev)
{
    if (dev->device_state != DEVICE_STATE_OPERATIONAL) {
        return;
    }

    /* Simulated incoming ZCL commands would be processed here */
    /* In real implementation, this would check the radio receive buffer */

    /* Example simulated command processing: */
    static bool demo_done = false;
    if (!demo_done) {
        printf("\n[APP] Simulating incoming commands...\n");

        /* Simulate On command */
        light_handle_on_off_command(&dev->light, 0x01);

        /* Simulate brightness change */
        light_handle_level_command(&dev->light, 0x04, 180, 10);

        /* Simulate color temperature change to warm white */
        light_handle_color_temp_command(&dev->light, 370, 5);

        demo_done = true;
    }
}

static void network_maintenance(zigbee_device_context_t *dev)
{
    if (dev->device_state != DEVICE_STATE_OPERATIONAL) {
        return;
    }

    /* Periodic tasks */
    static uint32_t last_maintenance = 0;
    uint32_t now = hal_get_tick_ms();

    if (now - last_maintenance > 30000) { /* Every 30 seconds */
        /* Send periodic link status / keep-alive */
        printf("[MAINT] Sending periodic network status report\n");

        /* Check neighbor table, update routes, etc. */
        last_maintenance = now;
    }

    /* Check permit join timeout */
    permit_join_tick(dev);
}

int main(void)
{
    /* Initialize the device */
    device_init(&g_device);

    printf("=============================================\n");
    printf("  Starting Smart Light Bulb Application\n");
    printf("=============================================\n\n");

    /* If factory new, start commissioning automatically */
    if (g_device.is_factory_new || g_device.device_state == DEVICE_STATE_INIT) {
        printf("[APP] Factory new device - starting automatic commissioning\n");
        printf("[APP] Please ensure your Zigbee coordinator has permit join enabled\n");
        printf("[APP] The light will blink during network search...\n\n");

        /* Start the commissioning process */
        commissioning_start_network_steering(&g_device);
    } else {
        printf("[APP] Restored configuration, resuming operation\n");
        g_device.device_state = DEVICE_STATE_OPERATIONAL;

        /* Re-register endpoints */
        register_endpoints(&g_device);
    }

    /* Main application loop */
    int loop_count = 0;
    int max_loops = 100; /* Limit for demonstration */

    while (loop_count < max_loops) {
        hal_watchdog_feed();

        /* Run commissioning state machine */
        if (g_commissioning.state != COMMISSION_IDLE) {
            commissioning_tick(&g_device);
        }

        /* Process incoming Zigbee commands */
        process_incoming_commands(&g_device);

        /* Network maintenance */
        network_maintenance(&g_device);

        /* Update LED status indication */
        update_status_indication(&g_device);

        /* Small delay to prevent busy loop */
        hal_delay_ms(10);

        loop_count++;

        /* Break early if operational and demo commands processed */
        if (g_device.device_state == DEVICE_STATE_OPERATIONAL &&
            g_commissioning.state == COMMISSION_IDLE &&
            loop_count > 20) {
            break;
        }
    }

    /* Print final status */
    printf("\n=============================================\n");
    printf("  Final Device Status\n");
    printf("=============================================\n");
    printf("  State:         %s\n",
           g_device.device_state == DEVICE_STATE_OPERATIONAL ? "OPERATIONAL" :
           g_device.device_state == DEVICE_STATE_ERROR ? "ERROR" : "OTHER");
    printf("  PAN ID:        0x%04X\n", g_device.pan_id);
    printf("  Channel:       %u\n", g_device.channel);
    printf("  Short Address: 0x%04X\n", g_device.short_address);
    printf("  Light State:   %s\n",
           g_device.light.state == LIGHT_ON ? "ON" : "OFF");
    printf("  Brightness:    %u/254\n", g_device.light.brightness);
    printf("  Color Temp:    %u mireds (~%uK)\n",
           g_device.light.color_temp,
           g_device.light.color_temp > 0 ? 1000000 / g_device.light.color_temp : 0);
    printf("  Security:      %s\n",
           g_device.security.network_key_valid ? "Network Key Active" : "No Key");
    printf("  Factory New:   %s\n", g_device.is_factory_new ? "Yes" : "No");
    printf("=============================================\n");

    /* Demonstrate factory reset capability */
    printf("\n[APP] Demonstrating factory reset...\n");
    factory_reset(&g_device);

    printf("\n[APP] Smart Light Bulb firmware demonstration complete.\n");

    return 0;
}